const now = new Date();
const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

return [{
  json: {
    date_from: thirtyDaysAgo.toISOString().split('T')[0],
    date_to: now.toISOString().split('T')[0],
    analysis_date: now.toISOString(),
    threshold_absences: 3
  }
}];

const leaveRequests = $input.first().json;
const threshold = $node['Set Date Range (Last 30 Days)'].json.threshold_absences;

if (!Array.isArray(leaveRequests) || leaveRequests.length === 0) {
  return [{ json: { flagged_employees: [], total_requests: 0, has_alerts: false } }];
}

// Group absences by employee
const absencesByEmployee = {};

for (const req of leaveRequests) {
  const empId = req.employee_id;
  if (!absencesByEmployee[empId]) {
    absencesByEmployee[empId] = {
      employee_id: empId,
      employee_name: req.hr_employees ? `${req.hr_employees.first_name} ${req.hr_employees.last_name}` : 'Inconnu',
      employee_email: req.hr_employees ? req.hr_employees.email : null,
      position_title: req.hr_employees ? req.hr_employees.position_title : null,
      department_id: req.hr_employees ? req.hr_employees.department_id : null,
      absence_count: 0,
      total_days: 0,
      leave_types: [],
      requests: []
    };
  }
  absencesByEmployee[empId].absence_count += 1;
  absencesByEmployee[empId].total_days += req.duration_days || 1;
  absencesByEmployee[empId].leave_types.push(req.leave_type || 'non_specifie');
  absencesByEmployee[empId].requests.push({
    id: req.id,
    start_date: req.start_date,
    end_date: req.end_date,
    leave_type: req.leave_type,
    reason: req.reason,
    duration_days: req.duration_days || 1
  });
}

// Flag employees exceeding threshold
const flaggedEmployees = Object.values(absencesByEmployee)
  .filter(emp => emp.absence_count > threshold)
  .sort((a, b) => b.absence_count - a.absence_count)
  .map(emp => ({
    ...emp,
    leave_types: [...new Set(emp.leave_types)],
    risk_level: emp.absence_count > 6 ? 'critical' : emp.absence_count > 4 ? 'high' : 'moderate',
    absenteeism_rate: ((emp.total_days / 22) * 100).toFixed(1)
  }));

return [{
  json: {
    flagged_employees: flaggedEmployees,
    total_requests: leaveRequests.length,
    total_employees_analyzed: Object.keys(absencesByEmployee).length,
    flagged_count: flaggedEmployees.length,
    has_alerts: flaggedEmployees.length > 0,
    analysis_period: {
      from: $node['Set Date Range (Last 30 Days)'].json.date_from,
      to: $node['Set Date Range (Last 30 Days)'].json.date_to
    },
    threshold: threshold
  }
}];

const flaggedData = $node['Calculate Absenteeism per Employee'].json;
const aiAnalysis = $input.first().json;

// Build HTML table rows for flagged employees
let employeeRows = '';
for (const emp of flaggedData.flagged_employees) {
  const riskColor = emp.risk_level === 'critical' ? '#dc2626' : emp.risk_level === 'high' ? '#f59e0b' : '#3b82f6';
  const riskLabel = emp.risk_level === 'critical' ? 'CRITIQUE' : emp.risk_level === 'high' ? 'ELEVE' : 'MODERE';

  employeeRows += `
    <tr>
      <td style="padding: 8px; border-bottom: 1px solid #e5e7eb;">${emp.employee_name}</td>
      <td style="padding: 8px; border-bottom: 1px solid #e5e7eb;">${emp.position_title || '-'}</td>
      <td style="padding: 8px; border-bottom: 1px solid #e5e7eb; text-align: center; font-weight: bold;">${emp.absence_count}</td>
      <td style="padding: 8px; border-bottom: 1px solid #e5e7eb; text-align: center;">${emp.total_days}j</td>
      <td style="padding: 8px; border-bottom: 1px solid #e5e7eb; text-align: center;">${emp.absenteeism_rate}%</td>
      <td style="padding: 8px; border-bottom: 1px solid #e5e7eb; text-align: center;"><span style="background: ${riskColor}; color: white; padding: 2px 8px; border-radius: 4px; font-size: 11px;">${riskLabel}</span></td>
      <td style="padding: 8px; border-bottom: 1px solid #e5e7eb; font-size: 12px;">${emp.leave_types.join(', ')}</td>
    </tr>`;
}

// AI insights section
let aiSection = '';
if (aiAnalysis && aiAnalysis.insights) {
  aiSection = `
    <div style="background: #eff6ff; border-left: 4px solid #3b82f6; padding: 16px; border-radius: 4px; margin: 16px 0;">
      <h3 style="margin: 0 0 8px; color: #1e40af;">Analyse IA</h3>
      <p style="margin: 0; white-space: pre-wrap;">${aiAnalysis.insights}</p>
    </div>`;
  if (aiAnalysis.recommendations && Array.isArray(aiAnalysis.recommendations)) {
    aiSection += '<h3>Recommandations IA :</h3><ul>';
    for (const rec of aiAnalysis.recommendations) {
      aiSection += `<li>${rec}</li>`;
    }
    aiSection += '</ul>';
  }
} else if (aiAnalysis && aiAnalysis.error) {
  aiSection = `<p style="color: #9ca3af;"><em>Analyse IA indisponible : ${aiAnalysis.error}</em></p>`;
}

return [{
  json: {
    employee_table_html: employeeRows,
    ai_section_html: aiSection,
    flagged_count: flaggedData.flagged_count,
    total_analyzed: flaggedData.total_employees_analyzed,
    period_from: flaggedData.analysis_period.from,
    period_to: flaggedData.analysis_period.to,
    critical_count: flaggedData.flagged_employees.filter(e => e.risk_level === 'critical').length,
    high_count: flaggedData.flagged_employees.filter(e => e.risk_level === 'high').length,
    ai_raw: aiAnalysis
  }
}];
